// Validate + prep file from base64 body.
// Expected body: { filename, contentType, base64, request_id, kind: 'purchase'|'payment' }
const body = $input.first().json.body || {};
if (!body.base64 || !body.filename) {
  throw new Error('base64 эсвэл filename талбар дутуу');
}
const kind = (body.kind || 'purchase').toLowerCase();
const safeKind = ['purchase','payment'].includes(kind) ? kind : 'purchase';
const requestId = (body.request_id || 'no-id').replace(/[^a-zA-Z0-9_-]/g,'');
const dateStr = new Date().toISOString().slice(0,10);
const ext = (body.filename.split('.').pop() || 'jpg').toLowerCase();
const finalName = `${dateStr}_${requestId}_${safeKind}.${ext}`;
// base64 → Buffer
const rawB64 = body.base64.replace(/^data:[^;]+;base64,/,'');
const buf = Buffer.from(rawB64, 'base64');
return [{
  json: {
    filename: finalName,
    contentType: body.contentType || 'application/octet-stream',
    size: buf.length,
    request_id: requestId,
    kind: safeKind
  },
  binary: {
    data: {
      data: rawB64,
      mimeType: body.contentType || 'application/octet-stream',
      fileName: finalName
    }
  }
}];
